-- Replace correlation_id with typed columns for deterministic, tx-scoped
-- NATS JetStream deduplication (pyck#1124).
-- transaction_id: per-tx UUID v7 generated by gqltx at BeginTx.
-- trace_id / request_id: observability only.
-- Yolo migration: in-flight rows get a random transaction_id (dedup key lost
-- for them). Drain the outbox (UPDATE ... SET published_at=NOW() WHERE
-- published_at IS NULL) before running on production for clean transition.

ALTER TABLE "main-data".event_outbox
    DROP CONSTRAINT IF EXISTS event_outbox_correlation_id_check;

DROP INDEX IF EXISTS "main-data".idx_event_outbox_polling_v2;
DROP INDEX IF EXISTS "main-data".idx_event_outbox_correlation;

ALTER TABLE "main-data".event_outbox
    DROP COLUMN IF EXISTS correlation_id;

-- Temporary DEFAULT covers any in-flight rows; drop it immediately so
-- new inserts must supply transaction_id explicitly (per gqltx contract).
-- gen_random_uuid() (v4) is fine here: the DEFAULT only applies to the
-- backfill of existing rows whose dedup key is lost anyway (see header).
-- New inserts come from Go via uuidgql.GenerateV7UUID.
ALTER TABLE "main-data".event_outbox
    ADD COLUMN transaction_id uuid NOT NULL DEFAULT gen_random_uuid();
ALTER TABLE "main-data".event_outbox ALTER COLUMN transaction_id DROP DEFAULT;

ALTER TABLE "main-data".event_outbox
    ADD COLUMN trace_id character varying NULL,
    ADD COLUMN request_id character varying NULL;

-- Backfill rows emitted before tenant_id was written to the column (the old
-- SendCustomEvent path set correlation_id but not tenant_id; fixed alongside
-- this migration). The tenant is recoverable from the event payload.
UPDATE "main-data".event_outbox
    SET tenant_id = (payload->>'tenant_id')::uuid
    WHERE tenant_id IS NULL AND payload->>'tenant_id' IS NOT NULL;

-- tenant_id was nullable after the 20260327120000 migration. Promote to
-- NOT NULL: every outbox row is tenant-scoped now. Fail loud if any row is
-- still NULL after the backfill — that signals an unknown tenant-less emit
-- path upstream.
ALTER TABLE "main-data".event_outbox
    ALTER COLUMN tenant_id SET NOT NULL;

CREATE INDEX IF NOT EXISTS idx_event_outbox_polling_v2
    ON "main-data".event_outbox (next_retry_at NULLS FIRST, transaction_id, created_at)
    WHERE published_at IS NULL AND dead_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_event_outbox_transaction
    ON "main-data".event_outbox (transaction_id, created_at)
    WHERE published_at IS NULL AND dead_at IS NULL;

COMMENT ON COLUMN "main-data".event_outbox.transaction_id IS
    'Per-DB-transaction UUID v7 generated by gqltx at BeginTx. Used as the NATS message ID component for tx-scoped, restart-safe deduplication.';
COMMENT ON COLUMN "main-data".event_outbox.trace_id IS
    'OpenTelemetry trace ID at row emission. Observability only.';
COMMENT ON COLUMN "main-data".event_outbox.request_id IS
    'Server-generated request ID from OTel baggage. Observability only.';
